-- Default catalog by trade (611 items, imported from the industry-standard CSV)
-- + catalog versioning so masters can pull NEWER defaults without losing edits.
--
-- Decisions: all items are WORK (the CSV is a labour reference, no material column);
-- prices = orientative market hint where the CSV had one (256), else 0 (the
-- master sets their own) — so the price CHECK is relaxed from > 0 to >= 0.

-- 1. New trades (PAINTER/DRYWALL/FLOORING/DEMOLITION) and units (POINT/PERCENT).
ALTER TABLE user_trades       DROP CONSTRAINT user_trades_trade_check;
ALTER TABLE user_trades       ADD  CONSTRAINT user_trades_trade_check
    CHECK (trade IN ('ELECTRICAL', 'PLUMBING', 'TILING', 'BUILDER', 'PAINTER', 'DRYWALL', 'FLOORING', 'DEMOLITION', 'GENERAL', 'OTHER'));

ALTER TABLE catalog_templates DROP CONSTRAINT catalog_templates_trade_check;
ALTER TABLE catalog_templates ADD  CONSTRAINT catalog_templates_trade_check
    CHECK (trade IN ('ELECTRICAL', 'PLUMBING', 'TILING', 'BUILDER', 'PAINTER', 'DRYWALL', 'FLOORING', 'DEMOLITION', 'GENERAL', 'OTHER'));

ALTER TABLE catalog_items     DROP CONSTRAINT catalog_items_unit_check;
ALTER TABLE catalog_items     ADD  CONSTRAINT catalog_items_unit_check
    CHECK (unit IN ('M2', 'M', 'LINEAR_METER', 'PIECE', 'KG', 'HOUR', 'SET', 'M3', 'T', 'POINT', 'PERCENT'));

ALTER TABLE estimate_items    DROP CONSTRAINT estimate_items_unit_check;
ALTER TABLE estimate_items    ADD  CONSTRAINT estimate_items_unit_check
    CHECK (unit IN ('M2', 'M', 'LINEAR_METER', 'PIECE', 'KG', 'HOUR', 'SET', 'M3', 'T', 'POINT', 'PERCENT'));

ALTER TABLE catalog_templates DROP CONSTRAINT catalog_templates_unit_check;
ALTER TABLE catalog_templates ADD  CONSTRAINT catalog_templates_unit_check
    CHECK (unit IN ('M2', 'M', 'LINEAR_METER', 'PIECE', 'KG', 'HOUR', 'SET', 'M3', 'T', 'POINT', 'PERCENT'));

-- 2. Allow a 0 (empty) price — the master fills it in.
ALTER TABLE catalog_templates DROP CONSTRAINT catalog_templates_price_check;
ALTER TABLE catalog_templates ADD  CONSTRAINT catalog_templates_price_check
    CHECK (suggested_price >= 0);

ALTER TABLE catalog_items     DROP CONSTRAINT catalog_items_price_check;
ALTER TABLE catalog_items     ADD  CONSTRAINT catalog_items_price_check
    CHECK (default_price >= 0);

-- 3. Versioning columns. added_in_version = the catalog version a template first
--    appeared in (all current = 1). last_synced_catalog_version = the version a
--    master last pulled from (so "Add new from catalog" only offers newer items).
ALTER TABLE catalog_templates ADD COLUMN added_in_version INT NOT NULL DEFAULT 1;
ALTER TABLE users ADD COLUMN last_synced_catalog_version INT NOT NULL DEFAULT 0;

-- 4. Replace the starter templates with the full by-trade default set. Templates
--    are global read-only reference data (CatalogItem copies VALUES, not FKs), so
--    a delete + re-insert never touches any user's own catalog_items.
DELETE FROM catalog_templates;


-- 5. Existing users stay at version 0 (the column default) — their catalog was
--    seeded from the OLD thin starter templates, so the new by-trade default set
--    (v1) IS new to them. "Add new from catalog" therefore offers them the full
--    default catalog for their trades, de-duplicated against what they already
--    own (never overwrites prices). New users from here on are synced to the
--    current version on register/reset (CatalogTemplateService), so for them the
--    button shows nothing until a future v2+ ships. No UPDATE needed here.
